import React from 'react';
import { FoodSpot } from '../types';

interface FoodCardProps {
	spot: FoodSpot;
}

const FoodCard: React.FC<FoodCardProps> = ({ spot }) => {
	const renderStars = (rating: number) => {
		const stars = [];
		const fullStars = Math.floor(rating);
		const hasHalfStar = rating % 1 !== 0;

		for (let i = 0; i < fullStars; i++) {
			stars.push(<span key={i} className="text-yellow-400">★</span>);
		}
		if (hasHalfStar) {
			stars.push(<span key="half" className="text-yellow-400">☆</span>);
		}
		const emptyStars = 5 - Math.ceil(rating);
		for (let i = 0; i < emptyStars; i++) {
			stars.push(<span key={`empty-${i}`} className="text-gray-300">☆</span>);
		}
		return stars;
	};

	return (
		<div className="bg-white rounded-lg shadow-md p-4 hover:shadow-lg transition-shadow duration-200">
			<div className="flex justify-between items-start mb-2">
				<h3 className="text-lg font-bold text-gray-800 truncate">{spot.name}</h3>
				<span className={`text-xs px-2 py-1 rounded-full ${
					spot.open_now ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
				}`}>
					{spot.open_now ? 'Open Now' : 'Closed'}
				</span>
			</div>

			<div className="flex items-center mb-2">
				<div className="flex items-center mr-4">
					{renderStars(spot.rating)}
					<span className="ml-1 text-sm text-gray-600">({spot.rating})</span>
				</div>
				<span className="text-sm text-gray-600">{spot.distance} mi</span>
			</div>

			<div className="flex items-center justify-between mb-2">
				<span className="text-sm text-gray-600 capitalize">{spot.category}</span>
				{spot.price_range && (
					<span className="text-sm font-medium text-green-600">{spot.price_range}</span>
				)}
			</div>

			{spot.address && (
				<p className="text-sm text-gray-500 truncate mb-2">{spot.address}</p>
			)}

			{spot.phone && (
				<p className="text-sm text-gray-500">{spot.phone}</p>
			)}
		</div>
	);
};

export default FoodCard;
